export const readingPassages = [
  { id:1, title:"Working in a Team", category:"Work", text:"Working in a team is an important skill in many jobs. When people work together, they can share ideas and solve problems more quickly. A good team has members who listen to each other and respect different opinions. Every member should do their part. When one person has a problem, others can help. Teams that communicate well usually get better results.", questions:[{"q": "What can teams do better than individuals?", "options": ["Work longer hours", "Share ideas and solve problems more quickly", "Earn more money", "Follow rules more carefully"], "answer": 1}, {"q": "What do good team members do?", "options": ["Work alone mostly", "Listen to each other and respect opinions", "Compete with each other", "Avoid helping others"], "answer": 1}, {"q": "What helps teams get better results?", "options": ["Working in silence", "Having a strong leader only", "Communicating well", "Working faster individually"], "answer": 2}, {"q": "What should every team member do?", "options": ["Lead the team", "Do their part", "Work the longest hours", "Make all decisions"], "answer": 1}] },
  { id:2, title:"A Job Interview", category:"Work", text:"John has a job interview tomorrow. He is nervous but excited. He has prepared for the interview by reading about the company. He has chosen smart clothes to wear. He plans to arrive ten minutes early. John knows that first impressions are very important. He wants to show the employer that he is the right person for the job.", questions:[{"q": "How does John feel about his interview?", "options": ["Angry and upset", "Nervous but excited", "Calm and relaxed", "Tired and bored"], "answer": 1}, {"q": "How has John prepared?", "options": ["He practised singing", "He read about the company", "He bought new shoes", "He called the manager"], "answer": 1}, {"q": "Why does John plan to arrive early?", "options": ["To meet other candidates", "Because first impressions are important", "To check the office", "Because the interview starts early"], "answer": 1}, {"q": "What does John want to show?", "options": ["That he is experienced", "That he is the right person for the job", "That he needs the money", "That he knows the manager"], "answer": 1}] },
  { id:3, title:"Using the Internet Safely", category:"Technology", text:"The internet is a very useful tool, but it can also be dangerous if we are not careful. We should never share our personal information such as our address or phone number with strangers online. We should use strong passwords and change them regularly. It is also important to check that websites are safe before buying anything online. If something seems too good to be true online, it probably is.", questions:[{"q": "What should we never share online?", "options": ["Our interests", "Personal information like address or phone number", "Our opinions", "Our favourite websites"], "answer": 1}, {"q": "What should we do with our passwords?", "options": ["Share them with friends", "Write them on paper", "Use strong passwords and change them regularly", "Use the same one everywhere"], "answer": 2}, {"q": "What should we check before buying online?", "options": ["The website colour", "That the website is safe", "The website language", "That it is popular"], "answer": 1}, {"q": "What does 'too good to be true' suggest?", "options": ["It is a great deal", "Something may be false or dangerous", "The price is correct", "It is a limited offer"], "answer": 1}] },
  { id:4, title:"Time Management at Work", category:"Work", text:"Good time management is essential for success in any job. Workers who manage their time well are able to complete more tasks, meet deadlines, and feel less stressed. One effective method is to create a to-do list at the start of each day. Writing down your tasks helps you remember them and allows you to prioritize the most important ones. Another useful technique is to avoid distractions such as social media and unnecessary meetings.", questions:[{"q": "What is one benefit of good time management?", "options": ["Meeting more people", "Completing more tasks", "Working more hours", "Earning more money"], "answer": 1}, {"q": "What does a to-do list help workers do?", "options": ["Make phone calls", "Prioritize important tasks", "Avoid their manager", "Work from home"], "answer": 1}, {"q": "What should workers avoid?", "options": ["Email", "Distractions like social media", "Coffee breaks", "All team meetings"], "answer": 1}, {"q": "What do managers value?", "options": ["Those who work long hours", "Those who ask for help", "Those who organize time independently", "Those who never take breaks"], "answer": 2}] },
  { id:5, title:"Body Language in the Workplace", category:"Communication", text:"Body language is a form of non-verbal communication that plays an important role in professional settings. The way you sit, stand, and make eye contact can influence how others perceive you. For example, sitting up straight signals confidence and professionalism, while crossed arms may appear defensive. Eye contact shows that you are engaged and interested in the conversation. A firm handshake creates a positive first impression during interviews or business meetings.", questions:[{"q": "What does sitting up straight signal?", "options": ["Boredom", "Confidence and professionalism", "Nervousness", "Agreement"], "answer": 1}, {"q": "What can crossed arms appear to communicate?", "options": ["Confidence", "Interest", "Defensiveness", "Agreement"], "answer": 2}, {"q": "What does eye contact show?", "options": ["Aggression", "Boredom", "That you are engaged", "That you are tired"], "answer": 2}, {"q": "What creates a positive first impression?", "options": ["Smiling widely", "A firm handshake", "Sitting quietly", "Speaking loudly"], "answer": 1}] },
  { id:6, title:"Remote Work Challenges", category:"Work", text:"Working from home has become increasingly common in recent years. While it offers many benefits such as flexibility and no commute, it also presents unique challenges. Many remote workers struggle with maintaining a clear boundary between their professional and personal lives. Without the physical separation of an office, it can be difficult to switch off from work. Isolation is another concern, as remote employees may feel disconnected from their colleagues.", questions:[{"q": "What is one benefit of working from home?", "options": ["More meetings", "No commute", "Better salary", "Larger desk"], "answer": 1}, {"q": "What challenge do remote workers face?", "options": ["Too many office parties", "Maintaining work-life boundaries", "Lack of technology", "Long commutes"], "answer": 1}, {"q": "Why might remote employees feel isolated?", "options": ["They work too many hours", "They earn less", "They feel disconnected from colleagues", "They have no internet"], "answer": 2}, {"q": "What can help address remote work challenges?", "options": ["Longer hours", "Regular virtual meetings", "Working in silence", "Reducing breaks"], "answer": 1}] },
  { id:7, title:"The Growth of E-Learning", category:"Education", text:"E-learning has transformed the way people access education around the world. Online platforms allow learners of all ages to study new subjects and develop professional skills from the comfort of their homes. Unlike traditional classroom learning, e-learning offers flexibility in terms of when and where students study. This makes it particularly valuable for working adults. However, students may lack motivation without the structure of a classroom environment.", questions:[{"q": "What has e-learning transformed?", "options": ["Transportation", "The way people access education", "Healthcare", "Banking"], "answer": 1}, {"q": "Why is e-learning valuable for working adults?", "options": ["It is free", "It offers flexible study times", "It is faster than school", "It provides physical books"], "answer": 1}, {"q": "What is one drawback of e-learning?", "options": ["Too many teachers", "Lack of motivation without classroom structure", "Too expensive", "Too many assignments"], "answer": 1}, {"q": "Who benefits most from e-learning flexibility?", "options": ["Young children", "Full-time students", "Working adults", "Retired people"], "answer": 2}] },
  { id:8, title:"The Importance of Sleep", category:"Health", text:"Sleep is one of the most important factors for good health. Adults need between seven and nine hours of sleep per night to function properly. During sleep, the body repairs itself, the brain processes information, and the immune system strengthens. People who regularly get insufficient sleep are more likely to experience health problems such as obesity, heart disease, and depression. Experts recommend maintaining a consistent sleep schedule and avoiding screens before bed.", questions:[{"q": "How many hours do adults need?", "options": ["Five to six", "Seven to nine", "Ten to twelve", "Four to five"], "answer": 1}, {"q": "What does the body do during sleep?", "options": ["Exercise and grow", "Repair itself and process information", "Produce more energy", "Increase blood pressure"], "answer": 1}, {"q": "What can result from insufficient sleep?", "options": ["Better concentration", "Weight loss", "Depression and heart disease", "Stronger immune system"], "answer": 2}, {"q": "What do experts recommend before bed?", "options": ["Exercising", "Watching television", "Avoiding screens", "Eating a large meal"], "answer": 2}] },
  { id:9, title:"Recycling and the Environment", category:"Environment", text:"Recycling is the process of converting waste materials into new products. It helps reduce rubbish sent to landfills and conserves natural resources such as timber, water, and minerals. Recycling also saves energy because it requires less energy to produce a product from recycled materials than from raw materials. For example, recycling aluminium uses ninety-five percent less energy than producing it from scratch. Despite these benefits, recycling rates remain low in many countries.", questions:[{"q": "What does recycling convert waste into?", "options": ["Landfills", "New products", "Raw materials", "Energy"], "answer": 1}, {"q": "Why does recycling save energy?", "options": ["Factories work less", "Raw materials are not needed", "Recycled products need less energy to make", "Waste is burned"], "answer": 2}, {"q": "How much less energy does recycling aluminium use?", "options": ["Fifty percent", "Seventy percent", "Ninety-five percent", "Twenty percent"], "answer": 2}, {"q": "Why are recycling rates low in many countries?", "options": ["Too many factories", "Lack of public awareness", "Too much recycled material", "High product costs"], "answer": 1}] },
  { id:10, title:"Customer Loyalty Programmes", category:"Business", text:"Customer loyalty programmes are marketing strategies designed to encourage repeat business by rewarding customers for their purchases. Points-based systems, discount cards, and exclusive membership benefits are common examples. These programmes benefit both businesses and consumers. Companies gain a stable customer base, higher revenue, and valuable data about buying habits. Research shows that retaining an existing customer is significantly cheaper than acquiring a new one.", questions:[{"q": "What is the main purpose of loyalty programmes?", "options": ["To attract new customers only", "To encourage repeat business", "To increase product prices", "To reduce costs"], "answer": 1}, {"q": "What do companies gain from these programmes?", "options": ["Fewer staff", "Valuable customer data and higher revenue", "Lower costs", "Government support"], "answer": 1}, {"q": "What is cheaper according to research?", "options": ["Marketing campaigns", "Retaining existing customers", "Building new stores", "Training new staff"], "answer": 1}, {"q": "What determines a loyalty programme success?", "options": ["Advertising budget", "Whether rewards reflect customer needs", "Company size", "Number of products"], "answer": 3}] },
  { id:11, title:"Urban Green Spaces", category:"Environment", text:"Urban green spaces such as parks, gardens, and tree-lined streets provide significant benefits to city residents. They offer places for physical activity, relaxation, and social interaction. Research shows that access to green spaces reduces stress, lowers blood pressure, and improves mood. Beyond individual health benefits, green spaces help manage urban heat islands and improve air quality. As cities expand, green spaces are often sacrificed for new housing and commercial developments.", questions:[{"q": "What do urban green spaces contribute to?", "options": ["Industrial growth", "Physical and mental well-being", "Higher property values", "Increased traffic"], "answer": 1}, {"q": "What do green spaces do to stress?", "options": ["Increase it", "Have no effect", "Reduce it", "Double it"], "answer": 2}, {"q": "What environmental role do they play?", "options": ["They increase pollution", "They manage urban heat and improve air quality", "They reduce property values", "They replace transport"], "answer": 1}, {"q": "What happens to green spaces as cities expand?", "options": ["They increase", "They are protected", "They are often lost to development", "They move outside cities"], "answer": 2}] },
  { id:12, title:"The Psychology of Motivation", category:"Psychology", text:"Motivation is the driving force behind human behaviour. Psychologists distinguish between intrinsic motivation, which comes from internal satisfaction such as enjoyment or personal growth, and extrinsic motivation, which is driven by external rewards like money or praise. Research suggests that intrinsic motivation tends to produce more sustained effort and creativity. When people are externally rewarded for activities they already enjoy, this can undermine their natural interest — the overjustification effect.", questions:[{"q": "What is intrinsic motivation driven by?", "options": ["Money and rewards", "Internal satisfaction and personal growth", "Fear of consequences", "Social pressure"], "answer": 1}, {"q": "Which type produces more creativity?", "options": ["Extrinsic", "Both equally", "Neither", "Intrinsic"], "answer": 3}, {"q": "What is the overjustification effect?", "options": ["Being very enthusiastic", "External rewards undermining natural interest", "Feeling motivated by praise", "Working harder for no reason"], "answer": 1}, {"q": "Where is understanding motivation most important?", "options": ["In sports only", "In education and the workplace", "In government", "In personal relationships only"], "answer": 1}] },
  { id:13, title:"The Digital Divide", category:"Technology", text:"The digital divide refers to the gap between those who have access to modern information and communication technology and those who do not. This divide is shaped by income, education, geography, and age. In developing countries, limited internet infrastructure and high device costs prevent many people from accessing the digital economy. Those without digital access are increasingly excluded from economic opportunities, civic participation, and social connection.", questions:[{"q": "What does the digital divide refer to?", "options": ["A gap in coding skills", "Differences between rich and poor countries", "The gap in access to modern technology", "Cost of internet services"], "answer": 2}, {"q": "What factors shape the digital divide?", "options": ["Language and culture only", "Income, education, geography, and age", "Weather and climate", "Political systems"], "answer": 1}, {"q": "What consequence does lack of digital access create?", "options": ["Better community bonds", "Exclusion from economic and civic opportunities", "Higher education levels", "More face-to-face interaction"], "answer": 1}, {"q": "What is needed to bridge this divide?", "options": ["More social media", "Investment in infrastructure and digital literacy", "Reducing costs for businesses only", "Creating more tech companies"], "answer": 1}] },
  { id:14, title:"Fast Fashion", category:"Environment", text:"Fast fashion refers to the rapid production of high volumes of clothing at low prices. While it has made fashion more accessible, the industry has significant environmental and social consequences. The fashion industry is one of the world's largest polluters, consuming vast amounts of water and releasing toxic chemicals into waterways. Synthetic fabrics shed microplastics into the ocean. Garment workers in developing countries often work in unsafe conditions for very low wages.", questions:[{"q": "What characterises fast fashion?", "options": ["Slow careful production", "High prices and limited runs", "Rapid production at low prices", "Handmade sustainable clothing"], "answer": 2}, {"q": "What environmental problem do synthetic fabrics cause?", "options": ["Air pollution", "Microplastic pollution in oceans", "Soil erosion", "Forest destruction"], "answer": 1}, {"q": "What social issue exists in fast fashion?", "options": ["Too many workers", "Poor conditions and low wages", "Too high production costs", "Lack of demand"], "answer": 1}, {"q": "What does sustainable fashion advocate?", "options": ["Buying the latest trends", "Wearing only designer clothes", "Ethical production and buying less but better quality", "Opening more factories"], "answer": 2}] },
  { id:15, title:"Emotional Intelligence at Work", category:"Psychology", text:"Emotional intelligence, often abbreviated as EQ, refers to the ability to recognise, understand, manage, and effectively use emotions. Psychologist Daniel Goleman argued that EQ may be more important than IQ for professional success. In the workplace, high EQ enables individuals to navigate interpersonal relationships, resolve conflicts constructively, and lead teams with empathy. Unlike IQ, emotional intelligence can be developed through self-reflection, feedback, and deliberate practice.", questions:[{"q": "What does EQ stand for?", "options": ["Educational Quotient", "Emotional Quality", "Emotional Intelligence", "Effective Questioning"], "answer": 2}, {"q": "What did Goleman argue?", "options": ["EQ is less important than IQ", "EQ may be more important than IQ for success", "EQ cannot be measured", "EQ only matters in creative fields"], "answer": 1}, {"q": "What have studies linked high EQ to?", "options": ["Higher salaries", "Better leadership and lower staff turnover", "More technical skills", "Faster promotions"], "answer": 1}, {"q": "How is EQ different from IQ?", "options": ["EQ measures academic ability", "EQ cannot change", "EQ can be developed through practice", "IQ matters more in leadership"], "answer": 2}] },
  { id:16, title:"At the Library", category:"Daily Life", text:"The library is a quiet place to read and study. You can borrow books for free. Most libraries also have computers and internet access. People of all ages come to the library.", questions:[{"q": "What can you do at the library for free?", "options": ["Buy books", "Borrow books", "Use a printer", "Take classes"], "answer": 1}, {"q": "What else do most libraries have?", "options": ["A gym", "Computers and internet access", "A swimming pool", "A cafeteria"], "answer": 1}, {"q": "Who comes to the library?", "options": ["Only students", "Only children", "Only adults", "People of all ages"], "answer": 3}, {"q": "How is the library described?", "options": ["Noisy", "Expensive", "Quiet", "Dark"], "answer": 2}] },
  { id:17, title:"Going to the Market", category:"Daily Life", text:"Ahmed goes to the market every Saturday. He buys fruit, vegetables, and bread. The market is near his house. He likes to talk to the sellers. The food at the market is fresh and cheap.", questions:[{"q": "When does Ahmed go?", "options": ["Every Sunday", "Every Friday", "Every Saturday", "Every day"], "answer": 2}, {"q": "What does Ahmed buy?", "options": ["Clothes and shoes", "Fruit, vegetables, and bread", "Books and pens", "Meat and fish only"], "answer": 1}, {"q": "Where is the market?", "options": ["Far from his house", "Near his house", "In another city", "Next to his workplace"], "answer": 1}, {"q": "What is the food like?", "options": ["Expensive and old", "Fresh and cheap", "Frozen and packaged", "Cooked and ready"], "answer": 1}] },
  { id:18, title:"A New Job", category:"Work", text:"Sara started a new job last week. She works at a bank. Her manager is very helpful. Sara arrives at work at eight every morning. She finishes at four in the afternoon. She is happy with her new job.", questions:[{"q": "Where does Sara work?", "options": ["A hospital", "A school", "A bank", "A shop"], "answer": 2}, {"q": "What time does Sara arrive?", "options": ["Seven", "Eight", "Nine", "Ten"], "answer": 1}, {"q": "How does Sara feel about her job?", "options": ["Unhappy", "Worried", "Bored", "Happy"], "answer": 3}, {"q": "How is her manager?", "options": ["Strict", "Unhelpful", "Helpful", "Absent"], "answer": 2}] },
  { id:19, title:"Learning to Cook", category:"Daily Life", text:"Cooking is a useful skill for everyone. When you cook at home, you can save money and eat healthier food. Many people watch cooking videos online to learn new recipes. Some people take cooking classes. It is never too late to start cooking.", questions:[{"q": "What can cooking at home help you do?", "options": ["Spend more money", "Meet new people", "Save money and eat healthier", "Cook faster than in a restaurant"], "answer": 2}, {"q": "How do many people learn new recipes?", "options": ["Cookbooks only", "Online cooking videos", "Eating at restaurants", "Asking neighbours"], "answer": 1}, {"q": "What does the passage say about starting to cook?", "options": ["It is only for young people", "You need a lot of money", "It is never too late to begin", "You must take classes first"], "answer": 2}, {"q": "Where can people learn cooking more formally?", "options": ["Online only", "Cooking classes", "Restaurants", "Libraries"], "answer": 1}] },
  { id:20, title:"My Neighbourhood", category:"Daily Life", text:"I live in a quiet neighbourhood. There is a park near my home where children play after school. There is also a small supermarket and a pharmacy. My neighbours are friendly. I feel safe and comfortable where I live.", questions:[{"q": "How is the neighbourhood?", "options": ["Noisy and busy", "Quiet", "Near the city centre", "Far from shops"], "answer": 1}, {"q": "What do children do in the park?", "options": ["Study", "Play after school", "Work", "Sleep"], "answer": 1}, {"q": "What is near the writer home?", "options": ["A hospital and a school", "A park, supermarket, and pharmacy", "A factory and an office", "A beach and a hotel"], "answer": 1}, {"q": "How does the writer feel?", "options": ["Unsafe and unhappy", "Bored and lonely", "Safe and comfortable", "Tired and stressed"], "answer": 2}] },
  { id:21, title:"Electric Cars", category:"Technology", text:"Electric vehicles are becoming more common as countries try to reduce carbon emissions. Unlike petrol cars, electric vehicles produce no direct exhaust emissions. However, the electricity used to charge them may still come from fossil fuel sources. Battery range and charging infrastructure remain challenges, though advances in battery technology are addressing these concerns. Major manufacturers have committed to phasing out petrol and diesel models within the next two decades.", questions:[{"q": "Why are electric vehicles considered cleaner?", "options": ["They use less fuel", "They produce no direct exhaust emissions", "They are lighter", "They require less maintenance"], "answer": 1}, {"q": "What limits their environmental benefit?", "options": ["Their price", "Charging infrastructure", "Electricity may come from fossil fuels", "Battery size"], "answer": 2}, {"q": "What challenges remain?", "options": ["Too many colours", "Battery range and charging infrastructure", "Lack of government interest", "Too many manufacturers"], "answer": 1}, {"q": "What have manufacturers committed to?", "options": ["Building cheaper cars", "Phasing out petrol and diesel models", "Reducing electric production", "Making only hybrid cars"], "answer": 1}] },
  { id:22, title:"Globalisation and Culture", category:"Society", text:"Globalisation has made the world more connected, enabling the rapid spread of ideas, products, and cultural practices across borders. While this connectivity has enriched many cultures, it has also raised concerns about cultural homogenisation. Critics argue that dominant cultures disproportionately influence smaller societies, potentially eroding indigenous languages and values. Proponents counter that communities can adopt foreign influences while preserving their core identities.", questions:[{"q": "What does cultural homogenisation mean?", "options": ["Cultures becoming more diverse", "Cultures becoming increasingly similar", "Languages disappearing entirely", "Music becoming more popular"], "answer": 1}, {"q": "What do critics argue?", "options": ["Globalisation enriches too many cultures", "Dominant cultures may erode smaller ones", "It creates too much trade", "It makes travel expensive"], "answer": 1}, {"q": "What do proponents argue?", "options": ["Cultural exchange destroys values", "Communities can keep their identity while adopting influences", "Globalisation should be stopped", "Western culture is superior"], "answer": 1}, {"q": "What does 'indigenous' most likely mean?", "options": ["Foreign", "Modern", "Native or originating naturally in a place", "Scientific"], "answer": 2}] },
  { id:23, title:"The Rise of Misinformation", category:"Media", text:"Social media has dramatically accelerated the spread of misinformation — false information shared without necessarily intending to deceive. The consequences range from public health crises to political instability. Algorithms designed to maximise engagement often amplify sensational content regardless of its truthfulness. Addressing this challenge requires digital literacy education, platform accountability, and transparent fact-checking systems.", questions:[{"q": "How is misinformation different from disinformation?", "options": ["Misinformation is always political", "Misinformation can spread without intent to deceive", "Disinformation is less harmful", "They are identical"], "answer": 1}, {"q": "What role do algorithms play?", "options": ["They reduce misinformation", "They amplify sensational content regardless of truth", "They verify all content", "They only promote education"], "answer": 1}, {"q": "What real-world consequence is mentioned?", "options": ["Entertainment losses", "Public health crises", "Economic recessions", "Increased tourism"], "answer": 1}, {"q": "What does the passage recommend?", "options": ["Banning social media", "Government-controlled media", "Digital literacy and fact-checking", "Reducing internet access"], "answer": 2}] },
  { id:24, title:"Workplace Wellness", category:"Work", text:"Many organisations are investing in workplace wellness programmes to improve employee health and productivity. These initiatives may include subsidised gym memberships, mental health support, and flexible working arrangements. Proponents argue that healthier employees take fewer sick days and demonstrate higher engagement. However, critics caution that wellness programmes can place responsibility on individuals while ignoring systemic issues such as excessive workloads and poor management.", questions:[{"q": "What is one wellness initiative?", "options": ["Longer hours", "Subsidised gym memberships", "Reduced salaries", "More meetings"], "answer": 1}, {"q": "What do healthier employees do?", "options": ["Work longer hours", "Earn more", "Take fewer sick days", "Manage more people"], "answer": 2}, {"q": "What criticism exists?", "options": ["Too expensive", "They place responsibility on individuals while ignoring systemic issues", "They reduce profits", "They make employees too relaxed"], "answer": 1}, {"q": "What is needed for programmes to be effective?", "options": ["More funding", "Compulsory participation", "Structural changes addressing root causes", "More managers"], "answer": 2}] },
  { id:25, title:"Language and Thought", category:"Linguistics", text:"The Sapir-Whorf hypothesis proposes that the language one speaks influences how one perceives and thinks about the world. Research in cognitive linguistics has found evidence that speakers of different languages perceive colour, time, and space differently. Languages that use absolute spatial terms like north and south rather than left and right appear to influence how speakers orient themselves. However, the extent to which language shapes thought remains debated.", questions:[{"q": "What does the Sapir-Whorf hypothesis propose?", "options": ["Language has no effect on thought", "Language influences how we perceive the world", "All languages think alike", "Grammar determines intelligence"], "answer": 1}, {"q": "What does research suggest?", "options": ["All humans perceive colour identically", "Speakers of different languages may perceive space differently", "Language has no practical effects", "Grammar is universal"], "answer": 1}, {"q": "What example of linguistic influence is given?", "options": ["Musical ability", "Mathematical performance", "Spatial orientation using absolute vs relative terms", "Emotional responses"], "answer": 2}, {"q": "What does the passage conclude?", "options": ["It is proven beyond doubt", "It is completely false", "It remains subject to ongoing debate", "It only applies to spoken languages"], "answer": 2}] },
  { id:26, title:"Travelling by Train", category:"Travel", text:"Many people travel by train because it is fast and comfortable. Trains usually run on time. You can read, sleep, or look out the window during the journey. Train stations are usually in the centre of the city.", questions:[{"q": "Why do people travel by train?", "options": ["It is cheapest", "It is fast and comfortable", "It goes everywhere", "It is free"], "answer": 1}, {"q": "What can you do on a train?", "options": ["Cook food", "Drive", "Read, sleep, or look out the window", "Work in the kitchen"], "answer": 2}, {"q": "Where are train stations usually?", "options": ["Outside the city", "Near airports", "In the centre of the city", "Near schools"], "answer": 2}, {"q": "What does the passage say about schedules?", "options": ["Trains are often late", "Trains usually run on time", "Trains only run at night", "Trains are often cancelled"], "answer": 1}] },
  { id:27, title:"Exercise and Health", category:"Health", text:"Regular exercise is important for good health. It helps keep the heart strong and the body fit. Doctors recommend at least thirty minutes of exercise five days a week. Walking, swimming, and cycling are good forms of exercise.", questions:[{"q": "What does exercise help keep strong?", "options": ["Eyes", "Teeth", "The heart", "Hair"], "answer": 2}, {"q": "How much exercise is recommended?", "options": ["Ten minutes a day", "At least thirty minutes five days a week", "One hour every day", "Two hours on weekends only"], "answer": 1}, {"q": "Which is listed as a good form of exercise?", "options": ["Reading", "Cooking", "Swimming", "Sleeping"], "answer": 2}, {"q": "Why is exercise important?", "options": ["It makes you taller", "It is good for general health", "It makes you smarter", "It replaces sleep"], "answer": 1}] },
  { id:28, title:"Using Public Transport", category:"Environment", text:"Using public transport such as buses and trains is better for the environment than driving a private car. It produces less pollution because many people share one vehicle. Public transport also reduces traffic in cities. It can save people money on petrol and parking.", questions:[{"q": "Why is public transport better for the environment?", "options": ["It is free", "It produces less pollution", "It is always on time", "It is more comfortable"], "answer": 1}, {"q": "How does it reduce pollution?", "options": ["By using electric engines", "By going faster", "By sharing one vehicle among many people", "By travelling less distance"], "answer": 2}, {"q": "What other benefit does it offer?", "options": ["Reduces crime", "Reduces city traffic", "Improves health", "Creates jobs"], "answer": 1}, {"q": "How does it save money?", "options": ["Free tickets", "Reducing costs on petrol and parking", "Reducing repair costs", "Loyalty discounts"], "answer": 1}] },
  { id:29, title:"Internet Safety", category:"Technology", text:"The internet is useful, but it can also be dangerous if we are not careful. We should never share personal information such as our address or phone number with strangers online. We should use strong passwords and change them regularly. It is important to check that websites are safe before buying anything online.", questions:[{"q": "What should we never share online?", "options": ["Our interests", "Personal information like address or phone number", "Our opinions", "Our favourite websites"], "answer": 1}, {"q": "How should passwords be?", "options": ["Short and easy", "Same for all sites", "Strong and different for each site", "Only numbers"], "answer": 2}, {"q": "What should you do with suspicious emails?", "options": ["Reply with your password", "Forward it", "Delete it and do not reply", "Call the sender"], "answer": 2}, {"q": "When should we use only trusted websites?", "options": ["When reading news", "When watching videos", "When shopping or banking", "When sending emails"], "answer": 2}] },
  { id:30, title:"Volunteering", category:"Society", text:"Volunteering means giving your time and skills to help others without getting paid. Many people volunteer at hospitals, schools, and food banks. Volunteering can help you gain experience, meet new people, and feel a sense of purpose. Communities become stronger when people help each other.", questions:[{"q": "What does volunteering mean?", "options": ["Working for a high salary", "Helping others without payment", "Studying a new skill", "Managing a business"], "answer": 1}, {"q": "Where do many people volunteer?", "options": ["Hotels and restaurants", "Hospitals, schools, and food banks", "Airports and train stations", "Gyms and sports clubs"], "answer": 1}, {"q": "What can volunteering help you gain?", "options": ["A high salary", "Experience and a sense of purpose", "A university degree", "A driving licence"], "answer": 1}, {"q": "What happens when people help each other?", "options": ["Communities become competitive", "Communities become weaker", "Communities become stronger", "Nothing changes"], "answer": 2}] },
  { id:31, title:"Music Education", category:"Education", text:"Studying music has many benefits beyond learning to play an instrument. Children who receive music education often develop stronger memory, better concentration, and improved mathematical ability. Playing in a group teaches cooperation and listening skills. Music can also help manage emotions and reduce stress. Despite these benefits, music programmes in schools are often among the first to be cut when budgets are reduced.", questions:[{"q": "What skills do children develop through music?", "options": ["Only musical talent", "Memory, concentration, and mathematical ability", "Language skills only", "Physical fitness"], "answer": 1}, {"q": "What does playing in a group teach?", "options": ["Competition", "Cooperation and listening skills", "How to perform alone", "How to read music only"], "answer": 1}, {"q": "How can music affect emotions?", "options": ["It always causes excitement", "It has no effect", "It can help manage emotions and reduce stress", "It causes anxiety"], "answer": 2}, {"q": "What often happens to music programmes when budgets are cut?", "options": ["They receive more funding", "They expand", "They are among the first to be cut", "They move online"], "answer": 2}] },
  { id:32, title:"AI in Healthcare", category:"Technology", text:"Artificial intelligence is increasingly being used in healthcare to improve diagnosis and treatment planning. Machine learning algorithms can analyse medical imaging data to detect conditions such as cancer at earlier stages. AI-driven tools also assist in drug discovery. However, the integration of AI in healthcare raises questions about data privacy, algorithmic bias, and appropriate boundaries of machine decision-making. Most experts agree that AI should augment rather than replace human clinical judgement.", questions:[{"q": "How does AI assist with cancer detection?", "options": ["By performing surgery", "By analysing imaging to detect cancer earlier", "By prescribing medication", "By interviewing patients"], "answer": 1}, {"q": "What is one concern?", "options": ["AI is too slow", "Algorithmic bias and data privacy", "It is too expensive", "It cannot read images"], "answer": 1}, {"q": "What role should AI play?", "options": ["Replace doctors entirely", "Make all clinical decisions", "Augment rather than replace human judgement", "Administrative tasks only"], "answer": 2}, {"q": "What is essential for safe AI deployment?", "options": ["Unlimited funding", "Removing all regulations", "Robust regulatory frameworks", "Replacing all doctors"], "answer": 2}] },
  { id:33, title:"A Busy Morning", category:"Daily Life", text:"Tom wakes up at seven. He takes a shower and gets dressed. Then he eats breakfast with his family. He leaves home at eight and takes the bus to work. He arrives at the office at half past eight.", questions:[{"q": "What time does Tom wake up?", "options": ["Six", "Seven", "Eight", "Nine"], "answer": 1}, {"q": "What does Tom do after getting dressed?", "options": ["Goes to work", "Takes the bus", "Eats breakfast with his family", "Reads the newspaper"], "answer": 2}, {"q": "How does Tom travel to work?", "options": ["He drives", "He walks", "He takes the bus", "He cycles"], "answer": 2}, {"q": "What time does Tom arrive at the office?", "options": ["Eight o'clock", "Half past eight", "Nine o'clock", "Quarter to nine"], "answer": 1}] },
  { id:34, title:"Animals in Danger", category:"Environment", text:"Many animals around the world are in danger of becoming extinct. This happens because people destroy their natural habitats to build farms and cities. Pollution also harms animals and their environments. Some organisations work to protect endangered animals. Without action, many species will disappear forever.", questions:[{"q": "Why are many animals in danger?", "options": ["They are poorly adapted", "People destroy their natural habitats", "They cannot reproduce", "Climate is too cold"], "answer": 1}, {"q": "What else harms animals?", "options": ["Food shortages", "Pollution", "Tourism", "Noise"], "answer": 1}, {"q": "What do some organisations do?", "options": ["Study them only", "Sell them", "Work to protect them", "Move them abroad"], "answer": 2}, {"q": "What happens without action?", "options": ["Animals will adapt", "Animals will move", "Many species disappear forever", "Habitats recover"], "answer": 2}] },
  { id:35, title:"Studying Abroad", category:"Education", text:"More and more students choose to study in another country. Living abroad helps students improve their language skills and experience a new culture. It can also improve career opportunities. However, it can be expensive and lonely at first. Many students say that studying abroad changed their lives in a positive way.", questions:[{"q": "What skill can improve when living abroad?", "options": ["Cooking skills", "Language skills", "Sports skills", "Art skills"], "answer": 1}, {"q": "What career benefit does it offer?", "options": ["Guaranteed job offers", "Free accommodation", "Better career opportunities", "Higher starting salary"], "answer": 2}, {"q": "What challenge can it bring?", "options": ["Meeting too many people", "Learning too quickly", "Being expensive and lonely", "Too much free time"], "answer": 2}, {"q": "What do many students say?", "options": ["It was a waste of time", "It changed their lives positively", "It was too easy", "It was not worth the cost"], "answer": 1}] },
  { id:36, title:"A Healthy Workplace", category:"Work", text:"A healthy workplace is important for both employees and employers. When workers feel safe and respected, they are more productive and motivated. Good managers listen to their teams and solve problems fairly. Comfortable working conditions such as proper lighting and ergonomic furniture reduce tiredness and injury. Regular breaks and clear communication maintain a positive work environment.", questions:[{"q": "What happens when workers feel safe?", "options": ["They work fewer hours", "They earn more", "They become more productive", "They ask for promotions"], "answer": 2}, {"q": "What do good managers do?", "options": ["They ignore problems", "They listen to teams and solve problems fairly", "They reduce salaries", "They work the longest hours"], "answer": 1}, {"q": "What does ergonomic furniture reduce?", "options": ["Costs", "Tiredness and injury", "Meetings", "Absences only"], "answer": 1}, {"q": "What maintains a positive environment?", "options": ["Long hours", "Regular breaks and clear communication", "Strict dress codes", "Reducing staff"], "answer": 1}] },
  { id:37, title:"The History of the Internet", category:"Technology", text:"The internet began as a military project in the United States in the 1960s. By the 1980s, universities and research centres were using it to share information. The World Wide Web was invented in 1989 by Tim Berners-Lee, making the internet accessible to the public. Today, over five billion people use the internet for communication, education, commerce, and entertainment.", questions:[{"q": "When did the internet begin?", "options": ["The 1950s", "The 1960s", "The 1970s", "The 1980s"], "answer": 1}, {"q": "Why was the original network created?", "options": ["For entertainment", "For online shopping", "As a military project", "For business"], "answer": 2}, {"q": "Who invented the World Wide Web?", "options": ["Bill Gates", "Steve Jobs", "Tim Berners-Lee", "Elon Musk"], "answer": 2}, {"q": "How many people use the internet today?", "options": ["One billion", "Three billion", "Over five billion", "Ten billion"], "answer": 2}] },
  { id:38, title:"The Impact of Automation", category:"Technology", text:"Automation refers to machines and software performing tasks previously done by humans. While automation increases efficiency and reduces costs, it displaces workers from repetitive jobs in manufacturing, data entry, and customer service. Historical evidence from the Industrial Revolution suggests that technology eventually generates new employment opportunities, though the transition can be disruptive for workers without the skills required by the new economy.", questions:[{"q": "What does automation refer to?", "options": ["Manual labour", "Machines performing human tasks", "Training employees", "Outsourcing abroad"], "answer": 1}, {"q": "Which jobs are most displaced?", "options": ["Creative and artistic jobs", "Leadership roles", "Repetitive manufacturing and data entry", "Scientific research"], "answer": 2}, {"q": "What does historical evidence suggest?", "options": ["Technology reduces employment", "Technology creates no jobs", "Technology eventually generates new opportunities", "Workers never adapt"], "answer": 2}, {"q": "How are governments responding?", "options": ["Banning automation", "Reducing wages", "Investing in reskilling programmes", "Increasing manual labour"], "answer": 2}] },
  { id:39, title:"Climate Migration", category:"Society", text:"Climate change is increasingly driving human migration as rising sea levels, prolonged droughts, and extreme weather events make certain regions uninhabitable. The World Bank estimates that by 2050, over 200 million people could be forced to move within their own countries. Unlike refugees fleeing conflict, climate migrants often lack formal legal recognition under international law. The phenomenon disproportionately affects low-income nations that have contributed least to greenhouse gas emissions.", questions:[{"q": "What is driving climate migration?", "options": ["Political instability", "Economic inequality", "Rising seas, droughts, and extreme weather", "Cultural differences"], "answer": 2}, {"q": "What legal challenge do climate migrants face?", "options": ["Too many documents", "Lack of formal legal recognition", "Too many countries to choose", "They cannot work"], "answer": 1}, {"q": "Which countries are most affected?", "options": ["Wealthy nations", "Low-income nations that contributed least to emissions", "Nations with the most technology", "Countries near the North Pole"], "answer": 1}, {"q": "What does addressing climate migration require?", "options": ["Building more walls", "Both mitigation and adaptation strategies", "Reducing international aid", "Restricting all movement"], "answer": 1}] },
  { id:40, title:"The Science of Habits", category:"Psychology", text:"Habits are automatic behaviours triggered by specific cues in our environment. Every habit follows a neurological loop consisting of a cue, a routine, and a reward. Research shows that it takes on average 66 days to form a stable new habit, not the commonly cited 21 days. Keystone habits such as regular exercise tend to trigger positive change across multiple areas of life.", questions:[{"q": "What triggers a habit?", "options": ["A reward", "A conscious decision", "A cue in the environment", "A routine"], "answer": 2}, {"q": "What are the three parts of the habit loop?", "options": ["Plan, action, reflection", "Cue, routine, reward", "Trigger, response, memory", "Goal, effort, result"], "answer": 1}, {"q": "How long does it take to form a stable habit?", "options": ["21 days", "30 days", "66 days on average", "100 days"], "answer": 2}, {"q": "What are keystone habits?", "options": ["Very difficult habits", "Habits that trigger positive change in multiple areas", "Habits formed in childhood", "Exercise habits only"], "answer": 1}] },
  { id:41, title:"Coffee Break", category:"Daily Life", text:"Many people drink coffee in the morning. Coffee contains caffeine, which helps people feel more awake. Some people prefer tea instead. Both drinks are popular around the world.", questions:[{"q": "Why do people drink coffee in the morning?", "options": ["To sleep better", "To feel more awake", "To save money", "To stay warm"], "answer": 1}, {"q": "What does coffee contain?", "options": ["Sugar", "Milk", "Caffeine", "Vitamins"], "answer": 2}, {"q": "What do some people prefer?", "options": ["Juice", "Water", "Tea", "Soda"], "answer": 2}, {"q": "What does the passage say about tea?", "options": ["It is not popular", "It contains caffeine", "It is also popular worldwide", "It is only drunk in the morning"], "answer": 2}] },
  { id:42, title:"My Pet", category:"Daily Life", text:"I have a dog named Max. He is brown and white. Max is very friendly and loves to play. I take him for a walk every morning. He eats special dog food twice a day. Max is my best friend.", questions:[{"q": "What is the dog name?", "options": ["Bruno", "Charlie", "Max", "Rex"], "answer": 2}, {"q": "When does the writer walk Max?", "options": ["Every evening", "Every morning", "At lunchtime", "On weekends only"], "answer": 1}, {"q": "How often does Max eat?", "options": ["Once a day", "Three times a day", "Twice a day", "Only at night"], "answer": 2}, {"q": "How is Max described?", "options": ["Shy and quiet", "Friendly and loves to play", "Aggressive and loud", "Old and tired"], "answer": 1}] },
  { id:43, title:"Saving Water", category:"Environment", text:"Water is a precious resource that we must not waste. Simple actions can save a lot of water. Turn off the tap while brushing your teeth. Fix leaking pipes quickly. Take shorter showers instead of baths. Use a bucket when washing your car instead of a hose.", questions:[{"q": "What should you do while brushing teeth?", "options": ["Use more water", "Turn off the tap", "Use hot water", "Drink water"], "answer": 1}, {"q": "What should you do with leaking pipes?", "options": ["Ignore them", "Fix them quickly", "Cover them", "Report them"], "answer": 1}, {"q": "What is recommended instead of baths?", "options": ["Swimming", "Shorter showers", "Less washing", "Cold water only"], "answer": 1}, {"q": "What should you use when washing a car?", "options": ["A hose", "Any method", "A bucket", "A sponge only"], "answer": 2}] },
  { id:44, title:"Job Interview Tips", category:"Work", text:"A job interview is an important opportunity to show a company why you are the right person for the role. You should research the company before the interview. Dress professionally and arrive on time. During the interview, listen carefully and answer questions clearly. Show enthusiasm and confidence. After the interview, send a thank you email to the interviewer.", questions:[{"q": "What should you do before an interview?", "options": ["Buy new clothes", "Research the company", "Call the manager", "Prepare demands"], "answer": 1}, {"q": "How should you dress?", "options": ["Casually", "Professionally", "In sports clothes", "It does not matter"], "answer": 1}, {"q": "What should you do after the interview?", "options": ["Wait by the phone", "Send a thank you email", "Call the company daily", "Post on social media"], "answer": 1}, {"q": "What qualities should you show?", "options": ["Shyness and silence", "Enthusiasm and confidence", "Nervousness", "Speed and impatience"], "answer": 1}] },
  { id:45, title:"The Role of Arts", category:"Society", text:"Art, in its many forms, plays a vital role in human culture and society. Literature, music, visual art, and performance provide ways for people to express complex emotions, question assumptions, and understand experiences beyond their own. Societies that support the arts tend to foster greater creativity, critical thinking, and cultural identity. However, arts funding is often reduced during economic downturns, reflecting a view that the arts are a luxury rather than a necessity.", questions:[{"q": "What do the arts provide ways for people to do?", "options": ["Earn more money", "Express emotions and understand others", "Learn technical skills", "Avoid social responsibility"], "answer": 1}, {"q": "What happens in societies that support the arts?", "options": ["Economic growth only", "Greater creativity and cultural identity", "More political problems", "Less education"], "answer": 1}, {"q": "When is arts funding often reduced?", "options": ["During economic growth", "When there are too many artists", "During economic downturns", "When new governments are elected"], "answer": 2}, {"q": "What view does arts funding reduction reflect?", "options": ["Arts are always essential", "Arts are always luxury", "Arts are seen as luxury by some despite being a necessity", "Arts funding never changes"], "answer": 2}] },
  { id:46, title:"Critical Thinking", category:"Education", text:"Critical thinking — the ability to analyse information objectively and make reasoned judgements — has become essential in the twenty-first century. In an environment saturated with information, the capacity to evaluate sources, identify logical fallacies, and distinguish evidence from opinion is more important than ever. Educational theorists argue that traditional schooling does not adequately cultivate critical thinking. Employers consistently rank critical thinking among the most desirable graduate attributes.", questions:[{"q": "What is critical thinking?", "options": ["Memorising large amounts of information", "Analysing information objectively and making reasoned judgements", "Following instructions carefully", "Reading widely"], "answer": 1}, {"q": "What capacity is most important today?", "options": ["Speed of reading", "Evaluating sources and distinguishing evidence from opinion", "Writing quickly", "Speaking multiple languages"], "answer": 1}, {"q": "What criticism is made of traditional schooling?", "options": ["Too expensive", "Too much sport", "Does not adequately cultivate critical thinking", "Too many graduates"], "answer": 2}, {"q": "Why do employers value critical thinking?", "options": ["It makes employees faster", "It reduces training costs", "It is central to decision-making and adaptability", "It ensures obedience"], "answer": 2}] },
  { id:47, title:"Healthy Workplace Habits", category:"Work", text:"Good habits at work help you perform better and stay healthy. Taking regular short breaks improves concentration and reduces eye strain. Drinking enough water throughout the day keeps you alert. Keeping your desk organised reduces stress. It is also important to stand up and move around during long periods of sitting to protect your back and circulation.", questions:[{"q": "What do regular short breaks improve?", "options": ["Salary", "Concentration and reduces eye strain", "Relationships", "Memory"], "answer": 1}, {"q": "What does drinking water do?", "options": ["Makes you eat less", "Keeps you alert", "Reduces meetings", "Improves writing"], "answer": 1}, {"q": "Why should you keep your desk organised?", "options": ["To impress your manager", "To find things quickly and reduce stress", "To avoid cleaning", "To save space"], "answer": 1}, {"q": "Why is moving around important?", "options": ["To meet colleagues", "To protect your back and circulation", "To use the printer", "To get fresh air"], "answer": 1}] },
  { id:48, title:"Communication at Work", category:"Communication", text:"Effective communication is one of the most important skills in any workplace. It involves not only speaking clearly but also listening actively. Employees who communicate well can share ideas, resolve misunderstandings quickly, and build stronger working relationships. Email and messaging tools are useful for written communication, but face-to-face or video meetings are often better for complex discussions. Miscommunication can lead to mistakes, wasted time, and conflict.", questions:[{"q": "What does effective communication involve?", "options": ["Speaking only", "Writing emails only", "Speaking clearly and listening actively", "Using only digital tools"], "answer": 2}, {"q": "What can employees who communicate well do?", "options": ["Work less", "Earn more", "Share ideas and resolve misunderstandings", "Avoid all meetings"], "answer": 2}, {"q": "When are face-to-face meetings better?", "options": ["For quick questions", "For complex discussions", "For simple tasks", "For sending files"], "answer": 1}, {"q": "What can miscommunication lead to?", "options": ["Better teamwork", "Faster decisions", "Mistakes, wasted time, and conflict", "More creative ideas"], "answer": 2}] },
  { id:49, title:"The Power of Reading", category:"Education", text:"Reading regularly has significant benefits for the mind and mental health. It improves vocabulary, concentration, and critical thinking. Reading fiction develops empathy by allowing readers to experience different perspectives. Non-fiction reading expands knowledge and keeps the mind sharp. Research has found that people who read for at least six minutes a day experience a measurable reduction in stress levels.", questions:[{"q": "What does reading regularly improve?", "options": ["Physical fitness", "Vocabulary, concentration, and critical thinking", "Social skills only", "Mathematical ability"], "answer": 1}, {"q": "How does reading fiction develop empathy?", "options": ["By teaching grammar", "By showing different perspectives and lives", "By improving memory", "By reducing stress"], "answer": 1}, {"q": "How much reading reduces stress?", "options": ["Thirty minutes a day", "One hour a week", "At least six minutes a day", "Ten pages a week"], "answer": 2}, {"q": "What does the passage say about books in the digital age?", "options": ["They are no longer relevant", "They are effective for deep learning", "They are too expensive", "They are only for older people"], "answer": 1}] },
  { id:50, title:"Work Ethic and Success", category:"Work", text:"Many successful people say that hard work is the key to achieving their goals. A strong work ethic means arriving on time, meeting deadlines, and giving your best effort. People with a good work ethic are often reliable, honest, and willing to take on responsibility. Employers value these qualities because they lead to better results. However, working hard must be balanced with rest to avoid burnout and maintain long-term productivity.", questions:[{"q": "What does a strong work ethic include?", "options": ["Arriving late", "Avoiding responsibility", "Arriving on time and meeting deadlines", "Working without breaks"], "answer": 2}, {"q": "Why do employers value a good work ethic?", "options": ["It reduces salaries", "It leads to better results", "It reduces training needs", "It makes employees famous"], "answer": 1}, {"q": "What must hard work be balanced with?", "options": ["More hard work", "Socialising", "Rest", "Travel"], "answer": 2}, {"q": "Why is rest important?", "options": ["Increases salary", "Helps avoid burnout", "Impresses managers", "Reduces hours"], "answer": 1}] },
];


